import React, { useState, useEffect } from 'react';
import Calendar from 'react-calendar';
import { historyAPI } from '../services/api';
import './CalendarCustom.css';
import 'react-calendar/dist/Calendar.css';
import { FiCalendar, FiChevronLeft, FiChevronRight } from 'react-icons/fi';

const CalendarPage = () => {
  const [date, setDate] = useState(new Date());
  const [outfitHistory, setOutfitHistory] = useState([]);
  const [selectedOutfit, setSelectedOutfit] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchOutfitHistory();
  }, []);

  const fetchOutfitHistory = async () => {
    try {
      setLoading(true);
      const response = await historyAPI.getHistory();
      setOutfitHistory(response.data.history || []);
      setError('');
    } catch (err) {
      console.error('Error fetching history:', err);
      setError('Failed to load outfit history');
    } finally {
      setLoading(false);
    }
  };

  const getOutfitsForDate = (selectedDate) => {
    return outfitHistory.filter(outfit => {
      const outfitDate = new Date(outfit.createdAt);
      return (
        outfitDate.getDate() === selectedDate.getDate() &&
        outfitDate.getMonth() === selectedDate.getMonth() &&
        outfitDate.getFullYear() === selectedDate.getFullYear()
      );
    });
  };

  const handleDateChange = (selectedDate) => {
    setDate(selectedDate);
    const outfits = getOutfitsForDate(selectedDate);
    setSelectedOutfit(outfits.length > 0 ? outfits[0] : null);
  };

  const hasOutfitOnDate = (date) => {
    return getOutfitsForDate(date).length > 0;
  };

  const selectedDayOutfits = getOutfitsForDate(date);

  return (
    <div className="calendar-container">
      <div className="calendar-header">
        <div className="header-content">
          <FiCalendar className="header-icon" />
          <h1>Outfit Calendar</h1>
          <p>Track your outfit history</p>
        </div>
      </div>

      <div className="calendar-content">
        {loading ? (
          <div className="loading">Loading outfit history...</div>
        ) : error ? (
          <div className="error-message">{error}</div>
        ) : (
          <>
            <div className="calendar-wrapper">
              <Calendar
                onChange={handleDateChange}
                value={date}
                tileClassName={({ date }) =>
                  hasOutfitOnDate(date) ? 'has-outfit' : ''
                }
                navigationLabel={({ date }) =>
                  date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })
                }
                prevLabel={<FiChevronLeft />}
                nextLabel={<FiChevronRight />}
              />
            </div>

            <div className="outfit-details">
              <div className="details-header">
                <h2>{date.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</h2>
              </div>

              {selectedDayOutfits.length > 0 ? (
                <div className="outfits-list">
                  {selectedDayOutfits.map((outfit, index) => (
                    <div key={outfit._id || index} className="outfit-card">
                      <div className="outfit-time">
                        {new Date(outfit.createdAt).toLocaleTimeString('en-US', {
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </div>
                      <div className="outfit-items">
                        <h3>Outfit #{index + 1}</h3>
                        {outfit.clothingItems && outfit.clothingItems.length > 0 ? (
                          <div className="calendar-outfit-images" style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginTop: '10px' }}>
                            {outfit.clothingItems.map((item, idx) => (
                              <div key={idx} className="calendar-item-card" style={{ width: '80px', textAlign: 'center' }}>
                                {item.imageUrl && (
                                  <img 
                                    src={item.imageUrl} 
                                    alt={item.name || item.type} 
                                    crossOrigin="anonymous"
                                    style={{ width: '80px', height: '80px', objectFit: 'cover', borderRadius: '8px', border: '1px solid #eee' }}
                                  />
                                )}
                                <div style={{ fontSize: '10px', marginTop: '4px', color: '#666' }}>
                                  {item.color} {item.type}
                                </div>
                              </div>
                            ))}
                          </div>
                        ) : (
                          <p className="no-items">No items details available</p>
                        )}
                      </div>
                      {outfit.notes && (
                        <div className="outfit-notes">
                          <p>{outfit.notes}</p>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="no-outfit">
                  <p>No outfit recorded for this date</p>
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default CalendarPage;
